from __future__ import annotations
from dataclasses import dataclass, field
from datetime import date
from enum import Enum
from typing import List, Optional


class ControlType(str, Enum):
    TECHNICAL = "technical"
    PROCEDURAL = "procedural"
    CONTRACTUAL = "contractual"
    TRAINING = "training"


class MitigationStatus(str, Enum):
    OPEN = "open"
    IN_PROGRESS = "in_progress"
    DONE = "done"
    OVERDUE = "overdue"
    ACCEPTED = "accepted"  # risk accepted without full mitigation


@dataclass
class MitigationPlan:
    finding_id: str
    control_description: str
    control_type: ControlType
    owner: str                    # e.g. "ML Safety Lead — J. Okafor"
    due_date: date
    initial_risk_score: int       # score from AIA (0-16)
    target_residual_score: int    # expected score after control
    status: MitigationStatus = MitigationStatus.OPEN
    evidence_refs: List[str] = field(default_factory=list)
    actual_residual_score: Optional[int] = None
    closed_date: Optional[date] = None
    notes: str = ""

    def advance(self, today: date = None) -> None:
        """Promote status to OVERDUE if deadline has passed."""
        today = today or date.today()
        if self.status == MitigationStatus.OPEN and today > self.due_date:
            self.status = MitigationStatus.OVERDUE
        elif self.status == MitigationStatus.IN_PROGRESS and today > self.due_date:
            self.status = MitigationStatus.OVERDUE

    def close(self, actual_score: int, evidence: List[str], closed: date = None) -> None:
        """
        Mark the plan as done.  Raises ValueError if actual_score does not
        meet the target — caller must explicitly accept residual risk.
        """
        if actual_score > self.target_residual_score:
            raise ValueError(
                f"Actual residual score {actual_score} exceeds target "
                f"{self.target_residual_score}. Accept risk explicitly."
            )
        self.actual_residual_score = actual_score
        self.evidence_refs.extend(evidence)
        self.status = MitigationStatus.DONE
        self.closed_date = closed or date.today()

    def accept_risk(self, rationale: str, accepted_score: int) -> None:
        """Record explicit risk acceptance when full mitigation is not achievable."""
        self.notes += f"[Risk accepted] {rationale}"
        self.actual_residual_score = accepted_score
        self.status = MitigationStatus.ACCEPTED
        self.closed_date = date.today()


@dataclass
class MitigationRegister:
    agent_id: str
    aia_version: str
    plans: List[MitigationPlan] = field(default_factory=list)

    def add(self, plan: MitigationPlan) -> None:
        self.plans.append(plan)

    def overdue(self, today: date = None) -> List[MitigationPlan]:
        today = today or date.today()
        for p in self.plans:
            p.advance(today)
        return [p for p in self.plans if p.status == MitigationStatus.OVERDUE]

    def open_count(self) -> int:
        return sum(
            1 for p in self.plans
            if p.status in (MitigationStatus.OPEN, MitigationStatus.IN_PROGRESS)
        )

    def summary(self) -> dict:
        counts = {s.value: 0 for s in MitigationStatus}
        for p in self.plans:
            counts[p.status.value] += 1
        return {"agent": self.agent_id, "aia_version": self.aia_version, **counts}
